sp_angular_provider.script:
/* Use this Directive to show an opening scene with a label, icon and content for the suspense date.
// 
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Special License Rights
//  The Government's rights to use, display, or disclose this software are restricted.
//  Any reproduction of computer software, computer software documentation,
//  or portions thereof marked with this legend must also reproduce the markings. 
// Script Continued Below
//-----------------------------------------------------------------------------------------------------
// 2.8.5 | 2023-11-28 | raj | Updates to make work for TemplateTask
// 2.8.5 | 2023-11-07 | mmcc | STRY0145237 - Directive - Duration code changes in the Angular Provider 
//	and Macro files to match design
// 2.8.5 | 2023-05-11 | mmcc | STRY0141856 - Stretch- PLACEHOLDER- Office Control
//   Updated to move variables into the duration object to streamline the services and 
//   This had the added benefit of allowing the same service to be called from server and client.
//   Updated to change div to span on the main control so it would work in Tab Form with Tabs as well 
//		as the data table
// 2.8.1 | 2023-04-07 | raj | STRY0137371 - Icons to Represent Status
//  Created Directive
// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open
//  Added CONST_POPOVER_DELAY, isClosing, d.initTooltip, d.popoverDelay;
//  Added function _initTooltip(); in function _leaveTooltip() set isClosing = true;
//    in function _showDuration(event) set isClosing = false;
//
//-----------------------------------------------------------------------------------------------------
*/
function dtechDuration(getTemplateUrl, spModal, $timeout) {

	var dtechDirective = {
		restrict: 'E',
		// replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way, 
		// &: execute an expression in the context of the parent scope, ?: the binding is optional
		scope: {
			dtechIsDark:"<",
			dtechInDataTable:"<?",
			dtechExcludeWarning:"<",
			dtechIsModal: "<",
			dtechPopoverPlacement: '@?',
			dtechShowLabel: "<?",
			dtechTable: '@',
			dtechTaskSysId: '@',
			dtechToolTipOpen: "=?",
			dtechDurationObject: "<",
			dtechHideDate: "<?",
			dtechShowLongDates: "<?",
			dtechTaskTitle: "@?"
		},
		controller: directiveCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechDuration.html')
	};
	return dtechDirective;

	function directiveCtrl($scope, $attrs, $sce, $animate, dtechTaskService, dtechTemplateService) {

		var d = this;

		// have local per directive instead of global - TODO: get from a service
		var CONST_TEMP_WAIT_DURATION = 600;
		// STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
		var CONST_POPOVER_DELAY = 1200;
		var CONST_SPINNER_DELAY = 500;

		// STRY0145237 - Directive - update to local var
		var isOverTooltip = false;
		var isClosing = false;

		// STRY0145237 - Directive - Duration code; 
		var parentMouseLeaveTimeouts = [];  // added an array to collect each time mouse leave fires; need to cancel time-outs on destroy

		// Section: directive's function declarations to hide implementation details, sorted
		$scope.dtechToolTipOpen = false;

		d.enterTooltip = _enterTooltip;
		d.getImage = _getImage;
		d.getBtnClass = _getBtnClass;
		d.init = _init;

		// STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.leaveTooltip = _leaveTooltip;
		d.openModal = _openModal;
		d.parentMouseLeave = _parentMouseLeave;

		// STRY0139742 - Increase delaying when hover directives open; 
		d.popoverDelay = CONST_POPOVER_DELAY;  // added to set popover-popup-delay in the Macro HTML

		d.popoverTemplate = $scope.dtechDurationObject.objectType + '-popover-duration.html';

		d.showDuration = _showDuration;

		// Section: local functions
		// when the user hovers over the tooltip set over tooltip flag
		function _enterTooltip() {
			isOverTooltip = true;
		}

		function _getImage(){
			var imageName = "Schedule16.svg";
			if(!$scope.dtechExcludeWarning){
				if($scope.dtechDurationObject.objectType=='task'){
					var status = "";
					if($scope.dtechDurationObject && $scope.dtechDurationObject.status && $scope.dtechDurationObject.status.display_value){
						status = $scope.dtechDurationObject.status.display_value;
					}
					if(status=='Critical'){
						imageName="x_153465_discovert.Error16.svg";
					}
					if(status=='Warning'){
						imageName="x_153465_discovert.Warning16.svg";
					}
				} else if ($scope.dtechDurationObject.objectType=='templateTask'){
					if(($scope.dtechDurationObject && $scope.dtechDurationObject.warning) &&
						($scope.dtechDurationObject.warning.waitStatewithNoSubtasks ||
						$scope.dtechDurationObject.u_warning_projected_due_date_before_child.display_value=='true' ||
						$scope.dtechDurationObject.u_warning_projected_due_date_after_parent.display_value=='true')){
							imageName="x_153465_discovert.Warning16.svg";
					}
				}
			}
			// only change to white if dark and using original image
			if(imageName=="Schedule16.svg" && $scope.dtechIsDark==true){
				imageName = "x_153465_discovert.Duration_White16.svg";
			}
			return imageName;
		}

		function _getBtnClass(){
			var btnClassNames='';
			// if there is a datat field, then make sure the row is flexed
			if($scope.dtechHideDate!=true){
				btnClassNames = "flex-row ";
			}
			// if it is a dark btn, apply dark btn
			if($scope.dtechIsDark){
				btnClassNames += "dtech-dark-btn ";
			}
			// if in a data table use the data table cell btn class
			if($scope.dtechInDataTable){
				btnClassNames += "dtech-table-cell-btn ";
			}
			if(!$scope.dtechInDataTable && !$scope.dtechIsDark){
				btnClassNames += "dtech-border-none dtech-btn ";
			}
			return btnClassNames;
		}

		function _init(rawAttrs) {
			// 2.8.5 | 2023-11-07 | mmcc | STRY0145237 - Directive - Duration code changes to match design; 
			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechPopoverPlacement)) {
				$scope.dtechPopoverPlacement = "auto";
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechShowLabel)) {
				$scope.dtechShowLabel = false;
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechHideDate)) {
				$scope.dtechHideDate = false;
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechShowLongDates)) {
				$scope.dtechShowLongDates = true;
			}

			if (angular.isUndefined(rawAttrs.dtechInDataTable)) {
				$scope.dtechInDataTable = false;
			}

			// Set default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechTaskTitle)) {
				if($scope.dtechDurationObject){
					$scope.dtechTaskTitle = $scope.dtechDurationObject.durationTitle;
				}
			}

			$scope.dtechToolTipOpen = 
				angular.isDefined($attrs.dtechToolTipOpen) ?
				$scope.$parent.$eval($attrs.dtechToolTipOpen) : false;			
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (isClosing == true) {
				_leaveTooltip();
				isClosing = false;
			}
		}

		function _leaveTooltip() {
			isOverTooltip = false;
			$scope.dtechToolTipOpen = false;

			// STRY0139742 - Increase delaying when hover directives open; set true
			isClosing = true;
		}

		// Call this function in the Template html by d.openModal($event);
		// it is called when a user clicks on the opening scene or the open link in the hover popover
		function _openModal(event) {
			// STRY0145237 - Directive - Duration code changes to match design;  
			var title = $scope.dtechTaskTitle;
			if ($scope.dtechDurationObject.objectType=='templateTask' || 
				$scope.dtechDurationObject.objectType=='task') {
				x_153465_discovert.twJS.openDurationModal(spModal, title, $scope.dtechTable, $scope.dtechTaskSysId);

				// popover closes quickly and user is left watching the spinner before modal pops
				d.leaveTooltip();

				// modal is openened stop the row or cell click form raising
				event.stopPropagation();
			}

		}

		function _parentMouseLeave() {
			// STRY0145237 - Directive - Duration code changes to match design; 
			// we need to track each time the below fires so we cancel on destroy
			parentMouseLeaveTimeouts.push($timeout(function() {
				if(!isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION));
		}

		// STRY0145237 - Directive - Duration code changes to match design;
		// removed unused $event
		function _showDuration() {
			$scope.dtechToolTipOpen = true;

			// STRY0139742 - Increase delaying when hover directives open; set false
			isClosing = false;

			var durationObject = $scope.dtechDurationObject;
			if(!durationObject){
				durationObject = {};
				durationObject.taskId = $scope.dtechTaskSysId;
				durationObject.loaded = false;
			}

			if(!durationObject.loaded || durationObject.taskId != $scope.dtechTaskSysId){
				$scope.dtechDurationObject.loaded=false;
				if($scope.dtechDurationObject.objectType=='task'){
					dtechTaskService.getDurationInformation($scope.dtechTaskSysId).then(
						function(response){
							_responseRecieved(response);
						});
				} else if($scope.dtechDurationObject.objectType=='templateTask'){
					dtechTemplateService.getDurationInformation($scope.dtechTaskSysId).then(
						function(response){
							_responseRecieved(response);
							});
				}
			}
			$scope.dtechDurationObject = durationObject;
		}

		function _boldReason(reason, phraseToHighlight){
			var newReason = reason.toString();
			var lengthReason = newReason.length;
			var lowerReason = newReason.toLowerCase();
			var lowerPhraseToHighlight = phraseToHighlight.toLowerCase();
			var lengthPhraseToHighlight = phraseToHighlight.length;
			var found = lowerReason.indexOf(lowerPhraseToHighlight);
			if(found>0){
				$scope.dtechReasonStart = newReason.substring(0,found); 
				$scope.dtechReasonBold = newReason.substring(found, found + lengthPhraseToHighlight);
				$scope.dtechReasonEnd = newReason.substring(found + lengthPhraseToHighlight); 
			} else {
				$scope.dtechReasonStart = newReason;
				$scope.dtechReasonBold = ""; 
				$scope.dtechReasonEnd = ""; 
			}
		}

		function _responseRecieved(response){
			$timeout(function(){
				_setDTechObject(response.durationInformation);
				}, CONST_SPINNER_DELAY);
		}

		function _setDTechObject(dtechObject){
			$scope.dtechReasonStart = "";
			$scope.dtechDurationObject = dtechObject;
			$scope.dtechDurationObject.loaded = true;
			if($scope.dtechDurationObject && $scope.dtechDurationObject.status_reason && $scope.dtechDurationObject.status_reason.reason){
				if($scope.dtechDurationObject.status.display_value=='Critical'){
					_boldReason($scope.dtechDurationObject.status_reason.reason, 'overdue');
				} else if($scope.dtechDurationObject.status.display_value=='Warning'){
					_boldReason($scope.dtechDurationObject.status_reason.reason, ' due');
				}
			}
			if($scope.dtechReasonStart ==""){
				$scope.dtechReasonStart = $scope.dtechDurationObject.status_reason.reason;
			}

		}

		// STRY0145237 - Directive - Duration code changes to match design; added
		$scope.$on("$destroy", function (event) {
			// we tracked each time mouse leave fired, now we can cancel each time-out and remove from the array
			angular.forEach(parentMouseLeaveTimeouts, function(item) {
				$timeout.cancel(item);
				parentMouseLeaveTimeouts.splice(parentMouseLeaveTimeouts.indexOf(item), 1);
			});
		});

	} // end function directiveCtrl

	function link(scope, element, attrs, directiveCtrl) {
		// initialize the control
		// 2.8.5 | 2023-11-07 | mmcc | STRY0145237 - Directive - Duration code changes to match design; 
		// updated to pass attrs
		directiveCtrl.init(attrs);

		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over

		function _destroy() {
			element.remove();
		}
	}

}
